import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";


const FAQS = [
  { q: "How many tiles do I need for a 100 sq ft floor?", a: "It depends on tile size. For 12 x 12 inch tiles (1 sq ft each): 100 tiles + 10% waste = 110 tiles. For 18 x 18 inch tiles (2.25 sq ft each): ~45 tiles + 10% = 50 tiles. For 6 x 6 inch tiles (0.25 sq ft each): 400 tiles + 10% = 440 tiles. Enter your exact measurements for a precise count." },
  { q: "How much extra tile should I order for waste?", a: "Order 10% extra for simple rectangular rooms with straight cuts. Order 15% for rooms with diagonal tile layout. Order 20% for complex rooms with many cuts (multiple alcoves, diagonal patterns, large format tiles with more breakage). It is always better to order slightly more - dye lots change between orders, making exact matches impossible later." },
  { q: "How do I calculate tiles for a wall?", a: "Measure wall height and width in inches. Multiply to get total square inches. Divide by tile area in square inches. Add 10-15% for waste. Example: 8-ft tall  x  10-ft wide wall = 96\"  x  120\" = 11,520 sq in. With 4 x 4 tiles (16 sq in): 11,520  x  16 = 720 tiles + 10% = 792 tiles." },
  { q: "What size grout joint should I use?", a: "Recommended grout joint by tile type: rectified tiles (precision-cut, perfectly square edges): 1/16\". Standard porcelain/ceramic floor tiles: 1/8\". Handmade or tumbled tiles with irregular edges: 3/16\"-1/4\". Large format tiles (24 x 24\" or larger): 1/8\"-3/16\". Unsanded grout: joints up to 1/8\". Sanded grout: joints 1/8\" or larger." },
  { q: "What is a box of tiles and how many square feet does it cover?", a: "Tile boxes vary by manufacturer. Common coverage: 12 x 12\" tiles: often 45 sq ft/box (45 tiles). 18 x 18\" tiles: often 36 sq ft/box (16 tiles). 12 x 24\" tiles: often 48 sq ft/box (24 tiles). Mosaic sheets: 12 x 12\" sheets, varying total sq ft. Always check the manufacturer's box label for the exact coverage area." },
  { q: "How do I figure out the tile layout to minimize waste?", a: "Start tiles from the center of the room outward - this centers the pattern and makes edge cuts equal on both sides. For rectangular rooms, snap chalk lines through the center in both directions. Dry-lay tiles without adhesive first to visualize the layout. A row of tiles less than half a tile wide at the edge looks bad - adjust your starting point to avoid this." },
  { q: "How much does tile installation cost?", a: "US averages: Tile cost: $1-$20+/sq ft depending on material (ceramic, porcelain, natural stone). Labor cost: $4-$10/sq ft for basic floor installation, $6-$15/sq ft for walls, $8-$20+ for complex patterns or large format tiles. Total installed cost: $10-$40+/sq ft is common. Materials are typically 40-60% of the total project cost." },
  { q: "What is the difference between ceramic and porcelain tile?", a: "Porcelain tiles are fired at higher temperatures and have lower water absorption (<0.5%) - they're harder, denser, and more durable than ceramic. Ceramic tiles (water absorption 0.5-3%) are easier to cut and less expensive. Both work for floors; porcelain is better for high-traffic, wet, or exterior applications. Natural stone (marble, slate) requires sealing and more maintenance." },
];

const COMMON_TILES = [
  ["6 x 6 in", "36 sq in", "0.25 sq ft", "4 per sq ft"],
  ["12 x 12 in", "144 sq in", "1.00 sq ft", "1 per sq ft"],
  ["12 x 24 in", "288 sq in", "2.00 sq ft", "0.5 per sq ft"],
  ["18 x 18 in", "324 sq in", "2.25 sq ft", "0.44 per sq ft"],
  ["24 x 24 in", "576 sq in", "4.00 sq ft", "0.25 per sq ft"],
  ["3 x 6 in (subway)", "18 sq in", "0.125 sq ft", "8 per sq ft"],
];

export default function TileCalculator() {
  useCurrencyVersion();
  const [roomLength, setRoomLength] = useState(15);
  const [roomWidth, setRoomWidth] = useState(12);
  const [tileLength, setTileLength] = useState(12);
  const [tileWidth, setTileWidth] = useState(12);
  const [waste, setWaste] = useState(10);

  const roomArea = roomLength * roomWidth;
  const tileArea = (tileLength / 12) * (tileWidth / 12);
  const tilesNeeded = Math.ceil((roomArea / tileArea) * (1 + waste / 100));
  const tilesNoWaste = Math.ceil(roomArea / tileArea);
  const costEstLow = tilesNeeded * 1.5;
  const costEstHigh = tilesNeeded * 5;

  return (
    <>
      <SEOHead
        title="Free Tile Calculator Online - Calculate Tiles Needed for Any Project Instantly | CalcHive"
        description="Free online tile calculator. Calculate exactly how many tiles you need for any floor or wall project including waste instantly. 100% free for everyone, no signup required."
        canonical="/tile-calculator"
        keywords="free tile calculator, tile calculator online free, how many tiles do I need calculator free, floor tile calculator free, wall tile calculator free online"
        category="Construction Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-stone-600 dark:text-stone-400 bg-stone-100 dark:bg-stone-800/50 px-3 py-1 rounded-full mb-4 inline-block">Housing</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Tile Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free tile calculator to answer how many tiles do I need calculator free for floors and walls, including waste. This tile calculator online free also works as a floor tile calculator free and wall tile calculator free online.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <p className="text-sm font-semibold text-muted-foreground uppercase tracking-wide">Room Dimensions</p>
            <SliderInput id="rl" label="Room Length (ft)" value={roomLength} min={1} max={100} step={0.5} onChange={setRoomLength} format={v => `${v} ft`} testId="input-room-length" />
            <SliderInput id="rw" label="Room Width (ft)" value={roomWidth} min={1} max={100} step={0.5} onChange={setRoomWidth} format={v => `${v} ft`} testId="input-room-width" />
            <p className="text-sm font-semibold text-muted-foreground uppercase tracking-wide pt-2">Tile Dimensions</p>
            <SliderInput id="tl" label="Tile Length (inches)" value={tileLength} min={4} max={48} step={1} onChange={setTileLength} format={v => `${v}"`} testId="input-tile-length" />
            <SliderInput id="tw" label="Tile Width (inches)" value={tileWidth} min={4} max={48} step={1} onChange={setTileWidth} format={v => `${v}"`} testId="input-tile-width" />
            <SliderInput id="waste" label="Waste Factor" value={waste} min={5} max={25} step={1} onChange={setWaste} format={v => `${v}%`} testId="input-waste" helpText="Straight cuts: 10% - Diagonal layout: 15% - Complex: 20%" />
          </div>
          <motion.div key={`${roomLength}-${roomWidth}-${tileLength}-${tileWidth}-${waste}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-stone-600 to-stone-800 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Tiles Needed</p>
              <p className="text-7xl font-black text-white tracking-tight" data-testid="result-tiles">{tilesNeeded.toLocaleString()}</p>
              <p className="text-white/70 text-sm mt-1">tiles including {waste}% waste</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Room Area", value: `${roomArea.toFixed(1)} sq ft` },
                { label: "Tiles (no waste)", value: `${tilesNoWaste} tiles` },
                { label: "Est. Material Cost", value: `${formatCurrencyValue(costEstLow, { maximumFractionDigits: 0 })}-${formatCurrencyValue(costEstHigh, { maximumFractionDigits: 0 })}` },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-sm font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
            <p className="text-xs text-muted-foreground mt-3 text-center">Material cost estimate at $1.50-$5.00 per tile. Actual cost varies by tile type.</p>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate How Many Tiles You Need for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Room Area (sq ft) = Room Length  x  Room Width</p>
            <p>Tile Area (sq ft) = (Tile Length  x  12)  x  (Tile Width  x  12)</p>
            <p>Tiles (no waste) = ceil(Room Area  x  Tile Area)</p>
            <p>Tiles with waste = ceil(Room Area  x  Tile Area  x  (1 + waste%))</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Account for Waste in Any Tile Project</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Tile Size", "Area (sq in)", "Area (sq ft)", "Tiles per Sq Ft"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {COMMON_TILES.map(([size, sqin, sqft, perSqFt]) => {
                  const [tl, tw] = size.replace(" in", "").split(" x ").map(Number);
                  const currentMatch = tl === tileLength && tw === tileWidth;
                  return (
                    <tr key={size} className={`hover:bg-muted/30 ${currentMatch ? "bg-stone-50 dark:bg-stone-800/30 font-semibold" : ""}`}>
                      <td className="py-2.5 px-4 font-bold text-stone-600 dark:text-stone-400">{size}</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{sqin}</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{sqft}</td>
                      <td className="py-2.5 px-4 font-semibold text-foreground">{perSqFt}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Floor and Wall Tile Calculator for Everyone</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free construction tool on mobile or desktop to estimate materials quickly, compare project scenarios, and plan with less guesswork.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/tile-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


